#include <stdio.h>
#include <limits.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long X; scanf("%d %lld", &N, &X);
        long long mn = LLONG_MAX, mx = LLONG_MIN, val;
        for(int i=0;i<N;i++){
            scanf("%lld", &val);
            if(val < mn) mn = val;
            if(val > mx) mx = val;
        }
        if(mn <= X && X <= mx) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

