#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); X = int(next(it))
        mn = 10**18; mx = -10**18
        for _ in range(N):
            v = int(next(it))
            if v < mn: mn = v
            if v > mx: mx = v
        out.append('YES' if mn <= X <= mx else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

